1	import { type JSX, useEffect, useRef, useState } from 'react';
2	import { useTranslation } from 'react-i18next';
3	import { ICON_SIZE, Icons, type LucideLikeIcon } from '@bim-ai/ui';
4	
5	import { type TabKind, type ViewTab } from './tabsModel';
6	
7	/**
8	 * TabBar — spec §11.3.
9	 *
10	 * Horizontal strip of open-view tabs sitting between the TopBar and
11	 * the canvas. Each tab carries a `kind` icon, a truncated label, and a
12	 * close ✕ button. Trailing `+` opens an "add view" popover.
13	 */
14	
15	const TAB_KIND_ICON: Record<TabKind, LucideLikeIcon> = {
16	  plan: Icons.floor!,
17	  '3d': Icons.family!, // Component (cube) — used for 3D views
18	  'plan-3d': Icons.floor!,
19	  section: Icons.section!,
20	  sheet: Icons.sheet!,
21	  schedule: Icons.schedule!,
22	  agent: Icons.agent!,
23	};
24	
25	export interface TabBarProps {
26	  tabs: ViewTab[];
27	  activeId: string | null;
28	  onActivate: (id: string) => void;
29	  onClose: (id: string) => void;
30	  /** Called when the user clicks a "+ {kind}" entry in the trailing
31	   * popover. The kind names a target the host should resolve (e.g.
32	   * "+ Plan" → open the active level as a tab). */
33	  onAdd?: (kind: TabKind) => void;
34	  /** Called when the user drags a tab to a new position. The host
35	   * should run the `reorderTab` reducer with the same indices. */
36	  onReorder?: (fromIdx: number, toIdx: number) => void;
37	  /** Called when the user clicks "Close Inactive Views" — closes all
38	   * tabs except the currently active one. */
39	  onCloseInactive?: () => void;
40	}
41	
42	const ADDABLE_KINDS: TabKind[] = ['plan', '3d', 'plan-3d', 'section', 'sheet', 'schedule', 'agent'];
43	
44	export function TabBar({
45	  tabs,
46	  activeId,
47	  onActivate,
48	  onClose,
49	  onAdd,
50	  onReorder,
51	  onCloseInactive,
52	}: TabBarProps): JSX.Element {
53	  const { t } = useTranslation();
54	  const [popoverOpen, setPopoverOpen] = useState(false);
55	  const [dragSrc, setDragSrc] = useState<number | null>(null);
56	  const [dragOverIdx, setDragOverIdx] = useState<number | null>(null);
57	  const popoverRef = useRef<HTMLDivElement | null>(null);
58	  const tabBarRef = useRef<HTMLDivElement>(null);
59	
60	  // Click-outside closes the popover.
61	  useEffect(() => {
62	    if (!popoverOpen) return;
63	    const onDoc = (e: MouseEvent): void => {
64	      if (popoverRef.current && !popoverRef.current.contains(e.target as Node)) {
65	        setPopoverOpen(false);
66	      }
67	    };
68	    document.addEventListener('mousedown', onDoc);
69	    return () => document.removeEventListener('mousedown', onDoc);
70	  }, [popoverOpen]);
71	
72	  // Convert vertical scroll to horizontal scroll on the tab bar so a
73	  // regular mouse wheel (or two-finger vertical swipe) scrolls tabs.
74	  useEffect(() => {
75	    const el = tabBarRef.current;
76	    if (!el) return;
77	    const onWheel = (ev: WheelEvent): void => {
78	      if (Math.abs(ev.deltaX) > Math.abs(ev.deltaY)) return; // already horizontal
79	      ev.preventDefault();
80	      el.scrollLeft += ev.deltaY;
81	    };
82	    el.addEventListener('wheel', onWheel, { passive: false });
83	    return () => el.removeEventListener('wheel', onWheel);
84	  }, []);
85	
86	  // Scroll the active tab into view whenever activeId changes.
87	  useEffect(() => {
88	    if (!activeId || !tabBarRef.current) return;
89	    const activeEl = tabBarRef.current.querySelector<HTMLElement>(`[data-tab-id="${activeId}"]`);
90	    if (activeEl) {
91	      activeEl.scrollIntoView({ behavior: 'smooth', block: 'nearest', inline: 'nearest' });
92	    }
93	  }, [activeId]);
94	
95	  return (
96	    <div
97	      ref={tabBarRef}
98	      role="tablist"
99	      aria-label={t('workspace.openViews')}
100	      data-testid="view-tabs"
101	      className="flex items-end gap-0.5 overflow-x-auto border-b border-border bg-surface pt-1.5"
102	      style={{ height: 38 }}
103	    >
104	      {tabs.length === 0 ? (
105	        <div className="px-2 pb-1.5 text-xs text-muted">{t('workspace.noViewsOpen')}</div>
106	      ) : null}
107	      {tabs.map((tab, idx) => {
108	        const Icon = TAB_KIND_ICON[tab.kind] ?? Icons.floor!;
109	        const isActive = tab.id === activeId;
110	        const isDragOver = dragOverIdx === idx && dragSrc !== null && dragSrc !== idx;
111	        const truncated = tab.label.length > 22 ? tab.label.slice(0, 21) + '…' : tab.label;
112	        return (
113	          <div
114	            key={tab.id}
115	            role="tab"
116	            aria-selected={isActive}
117	            data-tab-id={tab.id}
118	            data-tab-index={idx}
119	            data-active={isActive ? 'true' : 'false'}
120	            data-drag-over={isDragOver ? 'true' : 'false'}
121	            draggable={Boolean(onReorder)}
122	            onDragStart={(e) => {
123	              if (!onReorder) return;
124	              setDragSrc(idx);
125	              e.dataTransfer.effectAllowed = 'move';
126	              try {
127	                e.dataTransfer.setData('text/plain', String(idx));
128	              } catch {
129	                /* some browsers throw on setData inside synthetic events */
130	              }
131	            }}
132	            onDragOver={(e) => {
133	              if (!onReorder || dragSrc === null) return;
134	              e.preventDefault();
135	              e.dataTransfer.dropEffect = 'move';
136	              if (dragOverIdx !== idx) setDragOverIdx(idx);
137	            }}
138	            onDragLeave={() => {
139	              if (dragOverIdx === idx) setDragOverIdx(null);
140	            }}
141	            onDrop={(e) => {
142	              if (!onReorder || dragSrc === null) return;
143	              e.preventDefault();
144	              if (dragSrc !== idx) onReorder(dragSrc, idx);
145	              setDragSrc(null);
146	              setDragOverIdx(null);
147	            }}
148	            onDragEnd={() => {
149	              setDragSrc(null);
150	              setDragOverIdx(null);
151	            }}
152	            className={[
153	              'group flex items-center gap-1.5 rounded-t-md border border-b-0 px-3 py-1.5 text-[12px] font-medium transition-colors',
154	              isActive
155	                ? 'border-border/60 bg-background text-foreground'
156	                : 'border-transparent text-muted/70 hover:bg-background/40 hover:text-foreground',
157	              isDragOver ? 'ring-2 ring-accent ring-offset-0' : '',
158	            ].join(' ')}
159	            style={
160	              isActive
161	                ? {
162	                    boxShadow: 'inset 0 -2px 0 0 var(--color-accent)',
163	                  }
164	                : undefined
165	            }
166	          >
167	            <button
168	              type="button"
169	              onClick={() => onActivate(tab.id)}
170	              aria-label={`${t(`workspace.tabs.${tab.kind}`)}: ${tab.label}`}
171	              className="flex items-center gap-1.5 rounded"
172	              title={`${t(`workspace.tabs.${tab.kind}`)} · ${tab.label}`}
173	              data-testid={`tab-activate-${tab.id}`}
174	            >
175	              <Icon
176	                size={13}
177	                aria-hidden="true"
178	                className={isActive ? 'text-accent' : 'text-muted'}
179	              />
180	              <span className="whitespace-nowrap">{truncated}</span>
181	            </button>
182	            <button
183	              type="button"
184	              onClick={(e) => {
185	                e.stopPropagation();
186	                onClose(tab.id);
187	              }}
188	              aria-label={t('workspace.closeTab', { label: tab.label })}
189	              data-testid={`tab-close-${tab.id}`}
190	              className={[
191	                'rounded p-0.5 hover:bg-surface-strong',
192	                isActive
193	                  ? 'opacity-50 hover:opacity-100'
194	                  : 'opacity-0 group-hover:opacity-50 group-hover:hover:opacity-100',
195	              ].join(' ')}
196	            >
197	              <Icons.close size={11} aria-hidden="true" />
198	            </button>
199	          </div>
200	        );
201	      })}
202	      <div className="relative ml-1 mb-1.5" ref={popoverRef}>
203	        <button
204	          type="button"
205	          onClick={() => setPopoverOpen((v) => !v)}
206	          aria-label={t('workspace.openNewView')}
207	          aria-expanded={popoverOpen}
208	          aria-haspopup="menu"
209	          data-testid="tab-add-button"
210	          className="flex h-6 w-6 items-center justify-center rounded text-muted hover:bg-surface-strong hover:text-foreground"
211	          style={{ fontSize: 16, lineHeight: 1 }}
212	        >
213	          +
214	        </button>
215	        {popoverOpen ? (
216	          <div
217	            role="menu"
218	            data-testid="tab-add-popover"
219	            className="absolute left-0 top-full z-30 mt-1 flex min-w-[180px] flex-col rounded-md border border-border bg-surface shadow-elev-2"
220	            ref={(el) => el?.querySelector<HTMLElement>('[role="menuitem"]')?.focus()}
221	            onKeyDown={(e) => {
222	              const items = Array.from(
223	                e.currentTarget.querySelectorAll<HTMLElement>('[role="menuitem"]'),
224	              );
225	              const idx = items.indexOf(document.activeElement as HTMLElement);
226	              if (e.key === 'ArrowDown') {
227	                e.preventDefault();
228	                items[(idx + 1) % items.length]?.focus();
229	              } else if (e.key === 'ArrowUp') {
230	                e.preventDefault();
231	                items[(idx - 1 + items.length) % items.length]?.focus();
232	              } else if (e.key === 'Escape') {
233	                e.preventDefault();
234	                setPopoverOpen(false);
235	              }
236	            }}
237	          >
238	            {ADDABLE_KINDS.map((kind) => {
239	              const Icon = TAB_KIND_ICON[kind];
240	              return (
241	                <button
242	                  key={kind}
243	                  type="button"
244	                  role="menuitem"
245	                  onClick={() => {
246	                    setPopoverOpen(false);
247	                    onAdd?.(kind);
248	                  }}
249	                  className="flex items-center gap-2 px-3 py-1.5 text-left text-xs text-foreground hover:bg-surface-strong"
250	                  data-testid={`tab-add-${kind}`}
251	                >
252	                  <Icon size={ICON_SIZE.chrome} aria-hidden="true" />
253	                  <span>+ {t(`workspace.tabs.${kind}`)}</span>
254	                </button>
255	              );
256	            })}
257	          </div>
258	        ) : null}
259	      </div>
260	      {onCloseInactive && tabs.length > 1 ? (
261	        <button
262	          type="button"
263	          data-testid="close-inactive-tabs"
264	          title="Close Inactive Views"
265	          onClick={onCloseInactive}
266	          className="mb-1.5 ml-1 flex items-center gap-1 rounded px-1.5 py-0.5 text-muted hover:bg-surface-strong hover:text-foreground"
267	          style={{ fontSize: 11, whiteSpace: 'nowrap' }}
268	        >
269	          <Icons.close size={10} aria-hidden="true" />
270	          <span>Close Inactive</span>
