247	function TopBarModePills({
248	  tablistId,
249	  mode,
250	  onModeChange,
251	}: {
252	  tablistId: string;
253	  mode: WorkspaceMode;
254	  onModeChange: (next: WorkspaceMode) => void;
255	}): JSX.Element {
256	  const { t } = useTranslation();
257	  const tabRefs = useRef<Map<WorkspaceMode, HTMLButtonElement>>(new Map());
258	  const setTabRef = useCallback(
259	    (id: WorkspaceMode) => (el: HTMLButtonElement | null) => {
260	      if (el) tabRefs.current.set(id, el);
261	      else tabRefs.current.delete(id);
262	    },
263	    [],
264	  );
265	
266	  const handleKey = useCallback(
267	    (event: KeyboardEvent<HTMLDivElement>) => {
268	      if (event.key !== 'ArrowRight' && event.key !== 'ArrowLeft') return;
269	      const idx = WORKSPACE_MODES.findIndex((m) => m.id === mode);
270	      if (idx < 0) return;
271	      const delta = event.key === 'ArrowRight' ? 1 : -1;
272	      const next = WORKSPACE_MODES[(idx + delta + WORKSPACE_MODES.length) % WORKSPACE_MODES.length];
273	      event.preventDefault();
274	      onModeChange(next.id);
275	      tabRefs.current.get(next.id)?.focus();
276	    },
277	    [mode, onModeChange],
278	  );
279	
280	  return (
281	    <div
282	      role="tablist"
283	      id={tablistId}
284	      aria-label={t('topbar.modesAriaLabel')}
285	      onKeyDown={handleKey}
286	      className="flex flex-1 items-center justify-center gap-1"
287	    >
288	      {WORKSPACE_MODES.map((m) => {
289	        const active = m.id === mode;
290	        const modeLabel = t(`topbar.modes.${m.id}`);
291	        return (
292	          <button
293	            key={m.id}
294	            ref={setTabRef(m.id)}
295	            type="button"
296	            role="tab"
297	            aria-selected={active}
298	            aria-keyshortcuts={m.hotkey}
299	            tabIndex={active ? 0 : -1}
300	            onClick={() => onModeChange(m.id)}
301	            data-active={active ? 'true' : 'false'}
302	            title={`${modeLabel} (${m.hotkey})`}
303	            className={[
304	              'relative rounded px-3 py-1.5 text-sm font-medium transition-colors',
305	              active ? 'text-accent' : 'text-muted hover:bg-surface hover:text-foreground',
306	            ].join(' ')}
307	            style={active ? { boxShadow: 'inset 0 -2px 0 0 var(--color-accent)' } : undefined}
308	          >
309	            {modeLabel}
310	            <span aria-hidden="true" className="ml-1.5 text-[10px] tabular-nums opacity-40">
311	              {m.hotkey}
312	            </span>
313	          </button>
314	        );
315	      })}
316	    </div>
317	  );
318	}
319	
320	function TopBarRight({
321	  theme,
322	  onThemeToggle,
323	  onCommandPalette,
324	  onSettings,
325	  collaboratorsCount,
326	  onCollaboratorsClick,
327	  avatarInitials,
328	  peers,
329	  perspectiveOptions,
330	  perspectiveValue,
331	  onPerspectiveChange,
332	  planStyleOptions,
333	  planStyleValue,
334	  onPlanStyleChange,
335	  hasPages,
336	  onSharePresentation,
337	  onOpen3dView,
338	  sourceViewChip,
339	}: {
340	  theme: 'light' | 'dark';
341	  onThemeToggle?: () => void;
342	  onCommandPalette?: () => void;
343	  onSettings?: () => void;
344	  collaboratorsCount?: number;
345	  onCollaboratorsClick?: () => void;
346	  avatarInitials?: string;
347	  peers?: Array<{ name?: string; color?: string }>;
348	  perspectiveOptions?: TopBarSelectOption[];
349	  perspectiveValue?: string;
350	  onPerspectiveChange?: (id: string) => void;
351	  planStyleOptions?: TopBarSelectOption[];
352	  planStyleValue?: string;
353	  onPlanStyleChange?: (id: string) => void;
354	  hasPages?: boolean;
355	  onSharePresentation?: () => void;
356	  /** F-112: opens a new 3D view tab directly. */
357	  onOpen3dView?: () => void;
358	  /** MRK-V3-03: pre-rendered SourceViewChip node (null when not in sheet view). */
359	  sourceViewChip?: JSX.Element | null;
360	}): JSX.Element {
361	  const { t, i18n } = useTranslation();
362	  const showSelects =
363	    (perspectiveOptions && perspectiveOptions.length > 0) ||
364	    (planStyleOptions && planStyleOptions.length > 0);
365	  return (
366	    <div className="flex items-center gap-1.5">
367	      {showSelects ? (
368	        <>
369	          {perspectiveOptions &&
370	          perspectiveOptions.length > 0 &&
371	          perspectiveValue !== undefined &&
372	          onPerspectiveChange ? (
373	            <TopBarSelect
374	              value={perspectiveValue}
375	              onChange={onPerspectiveChange}
376	              options={perspectiveOptions}
377	              label={t('topbar.perspective')}
378	            />
379	          ) : null}
380	          {planStyleOptions &&
381	          planStyleOptions.length > 0 &&
382	          planStyleValue !== undefined &&
383	          onPlanStyleChange ? (
384	            <TopBarSelect
385	              value={planStyleValue}
386	              onChange={onPlanStyleChange}
387	              options={planStyleOptions}
388	              label={t('topbar.planStyle')}
389	            />
390	          ) : null}
391	          <div className="mx-1 h-4 w-px bg-border" aria-hidden="true" />
392	        </>
393	      ) : null}
394	      <button
395	        type="button"
396	        onClick={hasPages ? onSharePresentation : undefined}
397	        disabled={!hasPages}
398	        aria-label="Share live presentation"
399	        title={hasPages ? 'Share live presentation' : 'Add a Page first'}
400	        style={{ background: 'var(--color-surface-strong)' }}
401	        className="flex items-center gap-1.5 rounded-md border border-border px-2.5 py-1 text-muted shadow-sm hover:bg-surface-strong hover:text-foreground disabled:cursor-not-allowed disabled:opacity-40"
402	      >
403	        <span style={{ fontSize: 'var(--text-sm)' }}>Share live presentation</span>
404	      </button>
405	      {sourceViewChip ?? null}
406	      <button
407	        type="button"
408	        onClick={onCommandPalette}
409	        aria-label={IconLabels.commandPalette}
410	        aria-keyshortcuts="Meta+K Control+K"
411	        className="flex items-center gap-1.5 rounded-md border border-border bg-surface px-2.5 py-1 text-xs font-medium text-muted shadow-sm hover:bg-surface-strong hover:text-foreground"
412	      >
413	        <Icons.commandPalette size={13} aria-hidden="true" />
414	        <span className="tabular-nums">⌘K</span>
415	      </button>
416	      {peers && peers.length > 0 ? (
417	        <>
418	          <div className="mx-0.5 h-4 w-px bg-border" aria-hidden="true" />
419	          <div
420	            data-testid="peer-avatars"
421	            className="flex items-center -space-x-1"
422	            aria-label={t('topbar.activeCollaborators')}
423	          >
424	            {peers.slice(0, 5).map((p, i) => (
425	              <div
426	                key={i}
427	                title={p.name ?? t('topbar.anonymous')}
428	                className="flex h-6 w-6 items-center justify-center rounded-full border-2 border-surface text-[9px] font-semibold text-foreground ring-0"
429	                style={{ backgroundColor: p.color ?? 'var(--color-surface-strong)', zIndex: 5 - i }}
430	              >
431	                {(p.name ?? '?').slice(0, 2).toUpperCase()}
432	              </div>
433	            ))}
434	          </div>
435	        </>
436	      ) : null}
437	      <IconButton
438	        Icon={Icons.collaborators}
439	        label={IconLabels.collaborators}
440	        onClick={onCollaboratorsClick}
441	        badge={collaboratorsCount}
