443	      <IconButton Icon={Icons.settings} label={IconLabels.settings} onClick={onSettings} />
444	      {onOpen3dView && (
445	        <button
446	          type="button"
447	          data-testid="topbar-3d-view"
448	          title="Open 3D View"
449	          onClick={onOpen3dView}
450	          className="relative inline-flex h-8 items-center justify-center rounded-md px-2 text-xs font-semibold text-muted transition-colors hover:bg-surface hover:text-foreground"
451	        >
452	          3D
453	        </button>
454	      )}
455	      <button
456	        type="button"
457	        data-testid="topbar-language-toggle"
458	        title={`Switch language (current: ${i18n.language.toUpperCase()})`}
459	        onClick={() => {
460	          const next = i18n.language === 'de' ? 'en' : 'de';
461	          void i18n.changeLanguage(next);
462	          localStorage.setItem('bim-ai:lang', next);
463	        }}
464	        className="relative inline-flex h-8 w-8 items-center justify-center rounded-md text-xs font-semibold text-muted transition-colors hover:bg-surface hover:text-foreground"
465	      >
466	        {i18n.language.toUpperCase()}
467	      </button>
468	      <IconButton
469	        Icon={theme === 'dark' ? Icons.themeLight : Icons.themeDark}
470	        label={theme === 'dark' ? IconLabels.themeLight : IconLabels.themeDark}
471	        onClick={onThemeToggle}
472	        data-testid="topbar-theme-toggle"
473	        data-current-theme={theme}
474	      />
475	      <div className="mx-0.5 h-4 w-px bg-border" aria-hidden="true" />
476	      <div
477	        aria-label={t('topbar.account')}
478	        title={avatarInitials ?? ''}
479	        className="flex h-7 w-7 items-center justify-center rounded-full border border-border bg-accent/15 text-[11px] font-semibold text-accent"
480	      >
481	        {(avatarInitials ?? '··').slice(0, 2).toUpperCase()}
482	      </div>
483	    </div>
484	  );
485	}
486	
487	function TopBarSelect({
488	  value,
489	  onChange,
490	  options,
491	  label,
492	}: {
493	  value: string;
494	  onChange: (v: string) => void;
495	  options: TopBarSelectOption[];
496	  label: string;
