const ADDABLE_KINDS: TabKind[] = ['plan', '3d', 'plan-3d', 'section', 'sheet', 'schedule', 'agent'];

function TopBarTabs({
  tabs,
  activeId,
  onActivate,
  onClose,
  onAdd,
  onReorder,
  onCloseInactive,
}: {
  tabs: ViewTab[];
  activeId: string | null;
  onActivate?: (id: string) => void;
  onClose?: (id: string) => void;
  onAdd?: (kind: TabKind) => void;
  onReorder?: (from: number, to: number) => void;
